use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct ChatMessage {
    sender_id: String,
    content: String,
}

struct RoomState {
    messages: Vec<ChatMessage>,
}

impl Default for RoomState {
    fn default() -> Self {
        RoomState { messages: Vec::new() }
    }
}

struct ChatManager {
    rooms: Mutex<HashMap<String, Arc<Mutex<RoomState>>>>
}

impl ChatManager {
    fn new() -> Self {
        ChatManager { rooms: Mutex::new(HashMap::new()) }
    }

    fn get_or_create_room(&self, room_id: &str) -> Arc<Mutex<RoomState>> {
        let mut rooms = self.rooms.lock().unwrap();
        if !rooms.contains_key(room_id) {
            let new_state = Arc::new(Mutex::new(RoomState::default()));
            rooms.insert(String::from(room_id), new_state);
        }
        Arc::clone(&rooms.get(room_id).unwrap().clone())
    }

    fn handle_message(&self, room_id: &str, message: ChatMessage) -> Result<(), String> {
        let room_arc = self.get_or_create_room(room_id);
        let mut state = match room_arc.lock() {
            Ok(guard) => guard,
            Err(_e) => return Err(format!("Poisoned lock for room {}", room_id).to_string()),
        };
        state.messages.push(message);
        Ok(())
    }
}

fn main() {
    let manager = ChatManager::new();
    let room_a_id = "general";
    let room_b_id = "tech";

    manager.handle_message(room_a_id, ChatMessage { sender_id: String::from("User1"), content: String::from("Hi all!") }).unwrap();
    manager.handle_message(room_b_id, ChatMessage { sender_id: String::from("DevA"), content: String::from("Starting thread.") }).unwrap();
    manager.handle_message(room_a_id, ChatMessage { sender_id: String::from("User2"), content: String::from("See you later.") }).unwrap();

    let final_state = manager.get_or_create_room(room_a_id).lock().unwrap().messages.len();
    println!("Total messages in {}: {}", room_a_id, final_state);
}

use std::time::{Duration, Instant};

struct SensorRegisters {
    cpu_load: u32,
    mem_usage: u32,
    temperature: i16,
}

impl SensorRegisters {
    fn read_all() -> Self {
        SensorRegisters {
            cpu_load: 0xDEADBEEF,
            mem_usage: 0xCAFEBABE,
            temperature: -50,
        }
    }
}

const THRESHOLD_CPU: u32 = 100;
const OUTPUT_PIN_DURATION: Duration = Duration::from_millis(50);

fn main() {
    let mut last_check_time = Instant::now();
    let mut output_active = false;

    loop {
        std::thread::sleep(Duration::from_millis(100));

        if last_check_time.elapsed() >= Duration::from_secs(1) {
            let registers = SensorRegisters::read_all();
            println!("Read cycle: CPU={:x}, MEM={:x}, TEMP={}", 
                registers.cpu_load, registers.mem_usage, registers.temperature);

            if registers.cpu_load > THRESHOLD_CPU {
                if !output_active {
                    println!("ALERT: CPU threshold crossed. Activating output pin.");
                    // Simulate setting GPIO high
                    std::thread::sleep(OUTPUT_PIN_DURATION);
                    output_active = true;
                }
            } else {
                if output_active {
                    println!("Clear: CPU back to normal. Deactivating output pin.");
                    // Simulate setting GPIO low
                    output_active = false;
                }
            }
            last_check_time = Instant::now();
        }
    }
}

use std::collections::HashMap;
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Deserialize, Serialize)]
struct JobConfig {
    job_id: String,
    input_path: String,
    params: HashMap<String, String>,
}

fn run_distributed_map_reduce(configs: Vec<JobConfig>) -> Result<HashMap<String, HashMap<String, String>>, Box<dyn std::error::Error>> {
    let mut results: HashMap<String, HashMap<String, String>> = HashMap::new();
    for config in configs.iter() {
        if config.job_id.is_empty() || config.input_path.starts_with("invalid") {
            continue;
        }

        println!("Processing job: {}", config.job_id);
        let mut partial_result = HashMap::new();
        partial_result.insert(format!("processed_{}(_)", config.job_id), format!("success"));
        partial_result.insert(String::from("status"), String::from("ok"));

        results.entry(config.job_id.clone()).or_insert_with(HashMap::new).extend(partial_result);
    }

    Ok(results)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut configs: Vec<JobConfig> = Vec::new();

    let mut params1 = HashMap::new();
    params1.insert(String::from("threads"), String::from("8"));
    configs.push(JobConfig { job_id: String::from("map_job_a"), input_path: String::from("/data/a.csv"), params: params1 });

    let mut params2 = HashMap::new();
    params2.insert(String::from("batch_size"), String::from("1000"));
    configs.push(JobConfig { job_id: String::from("reduce_job_b"), input_path: String::from("/data/b.json"), params: params2 });

    let mut params3 = HashMap::new();
    params3.insert(String::from("workers"), String::from("4"));
    configs.push(JobConfig { job_id: String::from(""), input_path: String::from("/data/c.txt"), params: params3 });

    match run_distributed_map_reduce(configs) {
        Ok(results) => println!("nSuccessfully processed {} jobs.nResults: {:?}", results.len(), results),
        Err(e) => eprintln!("Error running job runner: {}", e),
    }

    Ok(())
}

use std::collections::HashMap;

struct SymbolTable {
    symbols: HashMap<String, usize>,
}

impl SymbolTable {
    fn new() -> Self {
        SymbolTable { symbols: HashMap::new() }
    }

    fn define(&mut self, name: &str) {
        if !self.symbols.contains_key(name) {
            let index = self.symbols.len();
            self.symbols.insert(String::from(name), index);
        }
    }

    fn get(&self, name: &str) -> Option<&usize> {
        self.symbols.get(name)
    }
}

fn process_environment(scope: &SymbolTable) -> usize {
    let mut result = 0;
    for i in 0..2 { 
        result += 10 * (i + 1);
    }
    result
}

fn main() {
    let mut scope = SymbolTable::new();
    scope.define("global_var");
    scope.define("other_setting");

    let performance_score = process_environment(&scope);
    println!("Calculated score based on environment: {}", performance_score);
}

use std::collections::HashMap;
use std::error::Error;
use std::fmt;

trait Processor {
    fn process(&self) -> Result<(), Box<dyn Error>>; 
}

struct ImageProcessor { file_size: u64 } 
impl Processor for ImageProcessor {
    fn process(&self) -> Result<(), Box<dyn Error>> {
        println!("Processing image object of size {}", self.file_size);
        Ok(()) 
    }
}

struct DocumentProcessor { content_hash: String } 
impl Processor for DocumentProcessor {
    fn process(&self) -> Result<(), Box<dyn Error>> {
        println!("Document object validated with hash: {}", self.content_hash);
        Ok(()) 
    }
}

struct FileUploadManager { files: HashMap<String, Box<dyn Processor>> }

impl FileUploadManager {
    fn new() -> Self {
        FileUploadManager { files: HashMap::new() }
    }

    fn register_file(&mut self, key: String, processor: Box<dyn Processor>) {
        self.files.insert(key, processor);
    }

    fn handle_upload(&self) -> Result<(), Box<dyn Error>> {
        println!("Starting batch file processing...");
        for (name, processor) in &self.files {
            println!("n--- Handling {} ---", name);
            processor.process()?;
        }
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut manager = FileUploadManager::new();
    manager.register_file("user_photo.jpg".to_string(), Box::new(ImageProcessor { file_size: 1024 * 500 }));
    manager.register_file("report.pdf".to_string(), Box::new(DocumentProcessor { content_hash: "a1b2c3d4e5f6g7h8".to_string() }));

    manager.handle_upload()?;
    Ok(())
}
